// TRENDING - compares this week vs last week, shows growth rate
const NPM_USERNAME = 'monfortbrian';
const correctionNote = $input.first().json.wasCorrected ? `_✏️ Did you mean /${$input.first().json.correctedTo}? Showing results:_\n\n` : '';

let packages = [];
try {
  const profile = await this.helpers.httpRequest({ method: 'GET', url: `https://registry.npmjs.org/-/v1/search?text=maintainer:${NPM_USERNAME}&size=50` });
  packages = profile.objects.map(o => o.package.name);
} catch(e) {
  packages = ['n8n-nodes-csv-normalizer','n8n-nodes-mtn-momo','comprehensive-design-tokens','n8n-nodes-openmrs','n8n-nodes-dhis2','openmrs-sdk','n8n-nodes-rapidpro'];
}

// Get date ranges
const now = new Date();
const oneWeekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
const twoWeeksAgo = new Date(now - 14 * 24 * 60 * 60 * 1000);
const fmt = d => d.toISOString().split('T')[0];

const thisWeekStart = fmt(oneWeekAgo);
const thisWeekEnd = fmt(now);
const lastWeekStart = fmt(twoWeeksAgo);
const lastWeekEnd = fmt(oneWeekAgo);

const results = [];

for (const pkg of packages) {
  try {
    const [thisWeek, lastWeek] = await Promise.all([
      this.helpers.httpRequest({ method: 'GET', url: `https://api.npmjs.org/downloads/point/${thisWeekStart}:${thisWeekEnd}/${pkg}` }),
      this.helpers.httpRequest({ method: 'GET', url: `https://api.npmjs.org/downloads/point/${lastWeekStart}:${lastWeekEnd}/${pkg}` })
    ]);
    const tw = thisWeek.downloads || 0;
    const lw = lastWeek.downloads || 0;
    const delta = tw - lw;
    const pct = lw > 0 ? Math.round((delta / lw) * 100) : (tw > 0 ? 100 : 0);
    const arrow = delta > 0 ? '🌱 ' : delta < 0 ? '⚠️' : '➖';
    results.push({ pkg, tw, lw, delta, pct, arrow });
  } catch (e) {
    results.push({ pkg, tw: 0, lw: 0, delta: 0, pct: 0, arrow: '🆕' });
  }
}

// Sort by absolute growth this week
results.sort((a, b) => b.tw - a.tw);

const winner = results[0];
const lines = results.map(r => {
  const sign = r.delta >= 0 ? '+' : '';
  return `  ${r.arrow} ${r.pkg}\n     This week: ${r.tw} | Last week: ${r.lw}  |  ${sign}${r.delta} (${sign}${r.pct}%)`;
});

const fmtDisplay = d => d.toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });

const message = [
  correctionNote + '🔥 *Trending Packages*',
  `_${fmtDisplay(twoWeeksAgo)} vs ${fmtDisplay(oneWeekAgo)} - ${fmtDisplay(now)}_`,
  '',
  `🏆 *Top this week: ${winner.pkg}* (${winner.tw} downloads)`,
  '',
  lines.join('\n'),
  '',
  '',
  '_Sorted by downloads this week._'
].join('\n');

return [{ json: { message, chatId: $input.first().json.chatId } }];

// MONTHLY DIGEST - 1st of every month 6PM GMT
const NPM_USERNAME = 'monfortbrian';

let packages = [];
try {
  const profile = await this.helpers.httpRequest({ method: 'GET', url: `https://registry.npmjs.org/-/v1/search?text=maintainer:${NPM_USERNAME}&size=50` });
  packages = profile.objects.map(o => o.package.name);
} catch(e) {
  packages = ['n8n-nodes-csv-normalizer','n8n-nodes-mtn-momo','comprehensive-design-tokens','n8n-nodes-openmrs','n8n-nodes-dhis2','openmrs-sdk','n8n-nodes-rapidpro'];
}

const now = new Date();
const today = now.toISOString().split('T')[0];

// Last month range
const lastMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0);
const lastMonthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);
// Two months ago for comparison
const twoMonthsStart = new Date(now.getFullYear(), now.getMonth() - 2, 1);
const twoMonthsEnd = new Date(now.getFullYear(), now.getMonth() - 1, 0);

const fmt = d => d.toISOString().split('T')[0];
const monthName = d => d.toLocaleDateString('en-GB', { month: 'long', year: 'numeric' });

const results = [];
let monthTotal = 0;
let prevMonthTotal = 0;
let grandTotal = 0;

for (const pkg of packages) {
  try {
    const [thisMonth, prevMonth, allTime] = await Promise.all([
      this.helpers.httpRequest({ method: 'GET', url: `https://api.npmjs.org/downloads/point/${fmt(lastMonthStart)}:${fmt(lastMonthEnd)}/${pkg}` }),
      this.helpers.httpRequest({ method: 'GET', url: `https://api.npmjs.org/downloads/point/${fmt(twoMonthsStart)}:${fmt(twoMonthsEnd)}/${pkg}` }),
      this.helpers.httpRequest({ method: 'GET', url: `https://api.npmjs.org/downloads/point/2020-01-01:${today}/${pkg}` })
    ]);
    const m = thisMonth.downloads || 0;
    const pm = prevMonth.downloads || 0;
    const a = allTime.downloads || 0;
    monthTotal += m;
    prevMonthTotal += pm;
    grandTotal += a;
    results.push({ pkg, m, pm, a });
  } catch(e) {
    results.push({ pkg, m: 0, pm: 0, a: 0 });
  }
}

results.sort((a, b) => b.m - a.m);

const delta = monthTotal - prevMonthTotal;
const sign = delta >= 0 ? '+' : '';
const arrow = delta > 0 ? '🌱' : delta < 0 ? '⚠️' : '➖';
const topPkg = results[0];

const message = [
  `*Monthly Report - ${monthName(lastMonthStart)}*`,
  '',
  `${arrow} Month-over-month: *${sign}${delta}* downloads vs ${monthName(twoMonthsStart)}`,
  '',
  `🏆 Top package: *${topPkg.pkg}* (${topPkg.m} downloads)`,
  '',
  '📊 *This Month vs Last Month*',
  results.map(r => {
    const d = r.m - r.pm;
    const s = d >= 0 ? '+' : '';
    return `  • ${r.pkg}: ${r.m} _(${s}${d})_`;
  }).join('\n'),
  `*Month Total: ${monthTotal.toLocaleString()}*`,
  '',
  '',
  '📦 *All-Time Totals*',
  results.map(r => `  • ${r.pkg}: ${r.a.toLocaleString()}`).join('\n'),
  `*Grand Total: ${grandTotal.toLocaleString()} downloads*`,
  '',
  '',
  '🔗 [View on npm](https://www.npmjs.com/~monfortbrian)'
].join('\n');

return [{ json: { message } }];

// MILESTONE CHECKER - runs daily at 9AM
// Alerts when a package crosses 100, 500, 1000, 5000, 10000 downloads
const NPM_USERNAME = 'monfortbrian';
const MILESTONES = [100, 500, 1000, 5000, 10000, 50000, 100000];

let packages = [];
try {
  const profile = await this.helpers.httpRequest({ method: 'GET', url: `https://registry.npmjs.org/-/v1/search?text=maintainer:${NPM_USERNAME}&size=50` });
  packages = profile.objects.map(o => o.package.name);
} catch(e) {
  packages = ['n8n-nodes-csv-normalizer','n8n-nodes-mtn-momo','comprehensive-design-tokens','n8n-nodes-openmrs','n8n-nodes-dhis2','openmrs-sdk','n8n-nodes-rapidpro'];
}

const today = new Date().toISOString().split('T')[0];
const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString().split('T')[0];

const alerts = [];

for (const pkg of packages) {
  try {
    const [todayData, yesterdayData] = await Promise.all([
      this.helpers.httpRequest({ method: 'GET', url: `https://api.npmjs.org/downloads/point/2020-01-01:${today}/${pkg}` }),
      this.helpers.httpRequest({ method: 'GET', url: `https://api.npmjs.org/downloads/point/2020-01-01:${yesterday}/${pkg}` })
    ]);
    const current = todayData.downloads || 0;
    const previous = yesterdayData.downloads || 0;

    for (const milestone of MILESTONES) {
      if (previous < milestone && current >= milestone) {
        alerts.push({ pkg, milestone, current });
      }
    }
  } catch(e) {}
}

if (alerts.length === 0) {
  return [{ json: { hasAlerts: false, message: null } }];
}

const lines = alerts.map(a => `🎉 *${a.pkg}* just crossed *${a.milestone.toLocaleString()} downloads!* (now at ${a.current.toLocaleString()})`);

const message = [
  '🏆 *Milestone Alert!*',
  '',
  lines.join('\n'),
  '',
  '_Keep shipping - the next milestone is closer than you think_'
].join('\n');

return [{ json: { hasAlerts: true, message } }];

