// Fuzzy command matcher - handles typos, slash or no slash, any case
function levenshtein(a, b) {
  const m = a.length, n = b.length;
  const dp = Array.from({length: m+1}, (_, i) => Array(n+1).fill(0).map((_, j) => i === 0 ? j : j === 0 ? i : 0));
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = a[i-1] === b[j-1] ? dp[i-1][j-1] : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
    }
  }
  return dp[m][n];
}

const raw = $input.first().json?.message?.text || '';
const chatId = $input.first().json?.message?.chat?.id;
const normalized = raw.trim().toLowerCase().replace(/^\//, '');

const commands = ['downloads', 'weekly', 'status', 'trending', 'help'];

let best = null;
let bestScore = Infinity;
for (const cmd of commands) {
  const score = levenshtein(normalized, cmd);
  if (score < bestScore) { bestScore = score; best = cmd; }
}

const matched = bestScore <= 4 ? best : 'unknown';
const wasCorrected = bestScore > 0 && bestScore <= 4 && normalized !== best;

return [{ json: { command: matched, original: raw, chatId, wasCorrected, correctedTo: best } }];

